import{_ as t,o as r,c as e,a2 as d}from"./chunks/framework.Cr-Z7ngm.js";const u=JSON.parse('{"title":"账户风控状态","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"margin/risk-control.md","filePath":"zh-CN/margin/risk-control.md"}'),i={name:"margin/risk-control.md"};function l(o,a,h,n,s,c){return r(),e("div",null,[...a[0]||(a[0]=[d('<h1 id="账户风控状态" tabindex="-1">账户风控状态 <a class="header-anchor" href="#账户风控状态" aria-label="Permalink to &quot;账户风控状态&quot;">​</a></h1><p>融资交易会影响账户风险等级。用户可在 App 资产页的融资状态入口查看当前风控状态及购买力影响。</p><p>注：适用版本为 4.0.1 及以上。</p><h2 id="风控状态等级" tabindex="-1">风控状态等级 <a class="header-anchor" href="#风控状态等级" aria-label="Permalink to &quot;风控状态等级&quot;">​</a></h2><p>风控状态分为 4 个等级：安全、中等、预警、危险。</p><h3 id="安全" tabindex="-1">安全 <a class="header-anchor" href="#安全" aria-label="Permalink to &quot;安全&quot;">​</a></h3><p>未使用融资。</p><h3 id="中等" tabindex="-1">中等 <a class="header-anchor" href="#中等" aria-label="Permalink to &quot;中等&quot;">​</a></h3><p>已使用融资，股权资产大于初始保证金要求。依照账户当前杠杆倍数判断，当前使用杠杆倍数越高，则风险越高。</p><h3 id="预警" tabindex="-1">预警 <a class="header-anchor" href="#预警" aria-label="Permalink to &quot;预警&quot;">​</a></h3><p>股权资产小于等于初始保证金要求，且股权资产大于维持保证金要求。</p><p>此时购买力已用尽，不可新增开仓。请关注持仓风险，如账户出现「应追缴保证金」金额，请及时补充资金或卖出股票补足欠款。</p><h3 id="危险" tabindex="-1">危险 <a class="header-anchor" href="#危险" aria-label="Permalink to &quot;危险&quot;">​</a></h3><p>股权资产小于等于维持保证金要求。</p><p>在此状态下，您的账户必须根据「应追缴保证金」的数值，在截止日 14:00 前存入足够的保证金或主动平仓部分头寸，否则账户会被强制平仓。券商有权自行决定平仓的股票、价格、数量和时间。</p><h2 id="字段解释" tabindex="-1">字段解释 <a class="header-anchor" href="#字段解释" aria-label="Permalink to &quot;字段解释&quot;">​</a></h2><ul><li>初始保证金要求：融资交易时要求的保证金，按照持仓股票市值的初始保证金率计算。当股权资产小于初始保证金要求时，购买力用尽，不可新开仓</li><li>维持保证金要求：维持保证金要求 = 账户持仓市值 × 账户持仓资产维持保证金率。当股权资产小于维持保证金要求时，将触发账户「危险」状态，需要平仓部分股票或者入金</li><li>股权资产 = 证券总价值 + 现金总价值 + 余额通总价值</li></ul><h2 id="应对措施" tabindex="-1">应对措施 <a class="header-anchor" href="#应对措施" aria-label="Permalink to &quot;应对措施&quot;">​</a></h2><table tabindex="0"><thead><tr><th>风控状态</th><th>限制</th><th>应对措施</th></tr></thead><tbody><tr><td>安全</td><td>无限制</td><td>无需操作</td></tr><tr><td>中等</td><td>无限制</td><td>关注杠杆倍数，控制风险</td></tr><tr><td>预警</td><td>不可新增开仓</td><td>补充资金或减仓，补足应追缴保证金</td></tr><tr><td>危险</td><td>不可新增开仓</td><td>在 14:00 前补足保证金或主动减仓，否则强制平仓</td></tr></tbody></table><hr><h2 id="相关文档" tabindex="-1">相关文档 <a class="header-anchor" href="#相关文档" aria-label="Permalink to &quot;相关文档&quot;">​</a></h2><ul><li><a href="/margin/追缴保证金规则">追缴保证金规则</a> — 追缴触发条件、处理期限与强制平仓说明</li><li><a href="/margin/融资额度与保证金规则">融资额度与保证金规则</a> — 保证金三层结构（IM/MM/FM）与购买力计算</li></ul>',22)])])}const b=t(i,[["render",l]]);export{u as __pageData,b as default};
